import{c as i,S as t,j as a,m as l}from"./chunks/framework.8aa1YH_s.js";const m=JSON.parse('{"title":"Luyện tập theo chuyên đề / module","description":"","frontmatter":{},"headers":[],"relativePath":"hoc-vien/luyen-tap.md","filePath":"hoc-vien/luyen-tap.md","lastUpdated":0}'),h={name:"hoc-vien/luyen-tap.md"};function o(r,n,g,e,c,s){return t(),a("div",null,[...n[0]||(n[0]=[l('<h1 id="luyen-tap-theo-chuyen-đe-module" tabindex="-1">Luyện tập theo chuyên đề / module <a class="header-anchor" href="#luyen-tap-theo-chuyen-đe-module" aria-label="Permalink to “Luyện tập theo chuyên đề / module”">​</a></h1><p><strong>Đường dẫn (bên trong khóa):</strong> <code>https://lamsonedutech.vn/luyen-tap/chi-tiet-luyen-tap/:id/:idCourse</code></p><p>Luyện tập là <strong>cách học chính</strong> trong khóa: làm các bài kiểm tra ngắn cuối từng chuyên đề, từng module, hoặc các bài tự luyện không giới hạn.</p><h2 id="cac-loai-bai-lam-trong-khoa" tabindex="-1">Các loại bài làm trong khóa <a class="header-anchor" href="#cac-loai-bai-lam-trong-khoa" aria-label="Permalink to “Các loại bài làm trong khóa”">​</a></h2><table tabindex="0"><thead><tr><th>Loại</th><th>Đặc điểm</th><th>Đường dẫn</th></tr></thead><tbody><tr><td><strong>Bài tập tự luyện</strong></td><td>Không giới hạn lần làm, có hiển thị đáp án ngay</td><td>Trong từng bài giảng</td></tr><tr><td><strong>Đề kiểm tra cuối chuyên đề</strong></td><td>Có thời gian, có điểm, có thể giới hạn số lần</td><td><code>https://lamsonedutech.vn/luyen-tap/kiem-tra-mo-dun/:idCourse/:idModule</code></td></tr><tr><td><strong>Đề ôn khóa học</strong></td><td>Đề tổng hợp toàn khóa, 1-3 lần làm</td><td><code>https://lamsonedutech.vn/luyen-tap/kiem-tra/:idCourse</code></td></tr></tbody></table><h2 id="bat-đau-mot-bai-luyen-tap" tabindex="-1">Bắt đầu một bài luyện tập <a class="header-anchor" href="#bat-đau-mot-bai-luyen-tap" aria-label="Permalink to “Bắt đầu một bài luyện tập”">​</a></h2><ol><li>Vào <strong>Khóa học của tôi</strong> → mở khóa.</li><li>Trong cây nội dung bên trái, tìm icon <strong>📝</strong> = bài kiểm tra.</li><li>Bấm vào → trang xem trước: <ul><li><strong>Tên đề</strong></li><li><strong>Số câu, thời gian</strong></li><li><strong>Số lần làm còn lại</strong></li><li><strong>Đề có hiển thị đáp án sau khi nộp?</strong></li></ul></li><li>Bấm <strong>Bắt đầu làm bài</strong>.</li></ol><h2 id="giao-dien-lam-bai" tabindex="-1">Giao diện làm bài <a class="header-anchor" href="#giao-dien-lam-bai" aria-label="Permalink to “Giao diện làm bài”">​</a></h2><h3 id="thanh-tren" tabindex="-1">Thanh trên <a class="header-anchor" href="#thanh-tren" aria-label="Permalink to “Thanh trên”">​</a></h3><ul><li><strong>Đồng hồ đếm ngược</strong> (mm:ss).</li><li>Tên đề, số câu đang làm / tổng.</li><li>Nút <strong>Lưu nháp</strong> (nếu hệ thống bật).</li></ul><h3 id="khu-vuc-cau-hoi-giua" tabindex="-1">Khu vực câu hỏi (giữa) <a class="header-anchor" href="#khu-vuc-cau-hoi-giua" aria-label="Permalink to “Khu vực câu hỏi (giữa)”">​</a></h3><ul><li>Đọc đề.</li><li>Có thể là: <ul><li><strong>Trắc nghiệm 4 đáp án (A/B/C/D)</strong> - chọn 1.</li><li><strong>Trắc nghiệm nhiều đáp án</strong> - chọn nhiều.</li><li><strong>Đúng / Sai</strong> - chọn 1.</li><li><strong>Điền số / Đáp án ngắn</strong> - gõ vào ô.</li><li><strong>Câu hỏi kèm đoạn văn / hình</strong> - đọc đoạn rồi trả lời.</li></ul></li></ul><h3 id="bang-đieu-huong-cau-phai" tabindex="-1">Bảng điều hướng câu (phải) <a class="header-anchor" href="#bang-đieu-huong-cau-phai" aria-label="Permalink to “Bảng điều hướng câu (phải)”">​</a></h3><ul><li>Lưới các số câu (1-50).</li><li>Màu sắc: <ul><li><strong>Xám</strong> = chưa làm</li><li><strong>Xanh</strong> = đã làm</li><li><strong>Vàng</strong> = đã đánh dấu xem lại</li><li><strong>Đỏ</strong> (chỉ sau nộp) = sai</li></ul></li><li>Bấm số câu để nhảy tới câu đó.</li></ul><h3 id="nut-duoi" tabindex="-1">Nút dưới <a class="header-anchor" href="#nut-duoi" aria-label="Permalink to “Nút dưới”">​</a></h3><ul><li><strong>Câu trước / Câu tiếp</strong></li><li><strong>Đánh dấu xem lại</strong> (lá cờ)</li><li><strong>Nộp bài</strong></li></ul><h2 id="quy-tac-khi-lam-bai" tabindex="-1">Quy tắc khi làm bài <a class="header-anchor" href="#quy-tac-khi-lam-bai" aria-label="Permalink to “Quy tắc khi làm bài”">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Tuyệt đối tránh</p><ul><li><strong>Tải lại trang (F5)</strong> - có thể mất bài nháp.</li><li><strong>Đóng tab / tắt trình duyệt</strong> trong khi đồng hồ đang chạy - bài có thể bị nộp tự động.</li><li><strong>Mở nhiều tab cùng làm bài</strong> - hệ thống chỉ ghi nhận 1 tab.</li></ul></div><div class="tip custom-block"><p class="custom-block-title">Nên làm</p><ul><li><strong>Lưu nháp</strong> sau mỗi 5-10 phút (nếu có nút).</li><li><strong>Đánh dấu cờ</strong> những câu còn nghi vấn, quay lại sau khi làm hết các câu chắc.</li><li><strong>Đảm bảo Internet ổn định</strong> trước khi bắt đầu.</li></ul></div><h2 id="khi-đong-ho-het" tabindex="-1">Khi đồng hồ hết <a class="header-anchor" href="#khi-đong-ho-het" aria-label="Permalink to “Khi đồng hồ hết”">​</a></h2><ul><li>Đồng hồ về 0:00 → hệ thống <strong>tự động nộp bài</strong>.</li><li>Tất cả câu đang dở dang được lưu theo trạng thái lúc đó.</li><li>Bạn không thể nhập thêm sau khi nộp.</li></ul><h2 id="sau-khi-nop-bai" tabindex="-1">Sau khi nộp bài <a class="header-anchor" href="#sau-khi-nop-bai" aria-label="Permalink to “Sau khi nộp bài”">​</a></h2><p>Hệ thống đưa bạn đến trang <strong>Kết quả</strong>:</p><ul><li><strong>Tổng điểm</strong> / tổng điểm tối đa</li><li><strong>Số câu đúng / sai / bỏ trống</strong></li><li><strong>Thời gian sử dụng</strong></li><li><strong>Xếp hạng</strong> (nếu đề công khai)</li></ul><h3 id="xem-lai-bai" tabindex="-1">Xem lại bài <a class="header-anchor" href="#xem-lai-bai" aria-label="Permalink to “Xem lại bài”">​</a></h3><ul><li>Bấm <strong>Xem lại bài</strong> → vào trang <code>https://lamsonedutech.vn/luyen-tap/xem-lai/:id</code>.</li><li>Xem từng câu: đáp án bạn chọn, đáp án đúng, lời giải (nếu giáo viên đăng).</li></ul><p>→ Xem <a href="./xem-lai-bai-thi">Xem lại bài thi</a>.</p><h2 id="lam-lai-bai" tabindex="-1">Làm lại bài <a class="header-anchor" href="#lam-lai-bai" aria-label="Permalink to “Làm lại bài”">​</a></h2><ul><li>Nếu đề cho phép, có nút <strong>Làm lại</strong>.</li><li>Số lần làm lại được hiển thị trên đề.</li><li>Mỗi lần làm lại có thể <strong>xáo trộn câu / đáp án</strong> để tránh học vẹt.</li></ul><h2 id="hoc-theo-lo-trinh-mo-khoa" tabindex="-1">Học theo lộ trình mở khóa <a class="header-anchor" href="#hoc-theo-lo-trinh-mo-khoa" aria-label="Permalink to “Học theo lộ trình mở khóa”">​</a></h2><p>Một số khóa yêu cầu <strong>đạt điểm tối thiểu</strong> ở bài kiểm tra mới mở chuyên đề kế.</p><p>Ví dụ:</p><ul><li>Bài kiểm tra cuối chuyên đề 1 cần ≥ 5/10 điểm.</li><li>Nếu &lt; 5 → bạn phải làm lại tới khi đủ điểm.</li><li>Cách tốt nhất: <strong>xem lại bài giảng yếu</strong> trước khi làm lại.</li></ul><h2 id="cau-hoi-thuong-gap" tabindex="-1">Câu hỏi thường gặp <a class="header-anchor" href="#cau-hoi-thuong-gap" aria-label="Permalink to “Câu hỏi thường gặp”">​</a></h2><p><strong>Tôi vừa làm xong nhưng hệ thống báo &quot;không lưu được kết quả&quot;.</strong> → Có thể mất kết nối lúc nộp. Đăng nhập lại → vào <strong>Lịch sử làm bài</strong> xem có bản nháp không. Nếu mất, liên hệ Hỏi đáp.</p><p><strong>Tôi bị đánh sai 1 câu mà rõ ràng đáp án em chọn đúng.</strong> → Vào <strong>Xem lại</strong> → chụp ảnh câu hỏi + đáp án → đặt câu hỏi trong Hỏi đáp dưới bài. Giáo viên sẽ kiểm tra.</p><p><strong>Tôi cần ngừng giữa chừng có được không?</strong> → Đồng hồ tiếp tục chạy ngay cả khi bạn đóng tab. Nếu muốn tạm dừng, hãy chắc chắn bạn có thời gian liền mạch để làm hết bài.</p><p><strong>Câu hỏi có công thức / hình ảnh không hiển thị.</strong> → Kiểm tra Internet. Reload trang (lưu ý: chỉ trước khi bắt đầu bài). Nếu vẫn lỗi, báo Hỏi đáp ngay.</p>',38)])])}const d=i(h,[["render",o]]);export{m as __pageData,d as default};
